Deriving a player class and calling the base initialization flow:

```cpp
class AActor {
public:
    virtual void BeginPlay() {
        // Basic actor initialization
    }
};

class ACharacter : public AActor {
public:
    // Override and invoke parent implementation
    void BeginPlay() override {
        AActor::BeginPlay(); // Call base version first!

        // Setup character health and mesh components
        SetupInputComponent();
    }

private:
    void SetupInputComponent() {}
};
```
